USE omicronvt;
GO

IF OBJECT_ID('dbo.vel_real_articulo', 'U') IS NOT NULL
    DROP TABLE dbo.vel_real_articulo;
GO

CREATE TABLE dbo.vel_real_articulo (
    codigo            VARCHAR(20)   NOT NULL,  -- codigo_sinonimo
    vel_aparente      DECIMAL(10,2) NOT NULL,  -- ventas_total / meses
    vel_real          DECIMAL(10,2) NOT NULL,  -- ventas_ok / meses_ok
    meses_con_stock   INT           NOT NULL,  -- meses sin quiebre
    meses_quebrado    INT           NOT NULL,  -- meses con stock_inicio <= 0
    factor_quiebre    DECIMAL(8,3)  NOT NULL,  -- vel_real / vel_aparente
    fecha_calculo     DATE          NOT NULL,  -- cuándo se calculó
    CONSTRAINT PK_vel_real_articulo PRIMARY KEY (codigo)
);
GO






















































































































































































































































































































































































































































































GO

-- Índice para JOINs desde calce/presupuesto
CREATE INDEX IX_vel_real_factor ON dbo.vel_real_articulo (codigo) INCLUDE (vel_real, factor_quiebre);
GO

